        'hero.desc':
            'Eine Open-Source-Erweiterung für neue Tabs mit hoher Anpassbarkeit.<br />8 Themes, 10 Sprachen und mehrere Hintergründe für deine Startseite.',
        'themes.title': '8 Themes, frei wechselbar',
